// Diagnostik: cek apakah ada vendor_id di MASTER_BAHAN yang tidak ada di MASTER_VENDOR
const Database = require('better-sqlite3');
const db = new Database('sqlite.db', { readonly: true });

try {
    // Cek apakah FK enforcement aktif
    const fkStatus = db.prepare("PRAGMA foreign_keys").get();
    console.log("Foreign keys enforcement:", fkStatus);

    // Cari bahan yang punya vendor_id tidak cocok
    const orphanBahan = db.prepare(`
        SELECT b.id, b.nama_bahan, b.vendor_id 
        FROM MASTER_BAHAN b 
        WHERE b.vendor_id IS NOT NULL 
        AND b.vendor_id NOT IN (SELECT id FROM MASTER_VENDOR)
    `).all();
    console.log("Orphan Bahan (vendor_id tidak cocok):", orphanBahan.length, "items");
    if (orphanBahan.length > 0) {
        console.log("Contoh:", orphanBahan.slice(0, 5));
    }

    // Cek daftar vendor yang ada
    const vendors = db.prepare("SELECT id, nama_vendor FROM MASTER_VENDOR").all();
    console.log("Total vendors:", vendors.length);
    vendors.forEach(v => console.log(`  - ${v.id}: ${v.nama_vendor}`));

    // Cek jumlah bahan
    const bahanCount = db.prepare("SELECT COUNT(*) as count FROM MASTER_BAHAN").get();
    console.log("Total bahan:", bahanCount.count);

    // Cek bahan dengan vendor_id
    const bahanWithVendor = db.prepare("SELECT DISTINCT vendor_id FROM MASTER_BAHAN WHERE vendor_id IS NOT NULL").all();
    console.log("Unique vendor_ids di MASTER_BAHAN:", bahanWithVendor.map(b => b.vendor_id));

} catch (e) {
    console.error(e);
}
db.close();

const xlsx = require('xlsx');
const path = require('path');

const filePath = path.join(__dirname, 'New folder', 'Kartu Stok - (Back To Mie Kitchen) - Back To Mie Kitchen - 03 Maret 2026 - Pawoon  (2).xls');
const workbook = xlsx.readFile(filePath);
const sheet = workbook.Sheets[workbook.SheetNames[0]];
const rawData = xlsx.utils.sheet_to_json(sheet, { header: 1 });

console.log('Total rows:', rawData.length);

// Header
console.log('\n=== HEADER (row 7) ===');
const header = rawData[7];
if (header) header.forEach((c, i) => console.log(`  [${i}]="${c}"`));

// Cari baris dengan Penjualan > 0
let found = 0;
for (let i = 8; i < rawData.length; i++) {
    const row = rawData[i];
    if (!row || row.length === 0) continue;
    const raw = row[5];
    let val = 0;
    if (typeof raw === 'number') val = raw;
    else if (typeof raw === 'string') val = parseFloat(raw.replace(',', '.'));
    if (val > 0) {
        found++;
        if (found <= 10) console.log(`Row ${i}: Produk="${row[0]}", Penjualan="${raw}" (type:${typeof raw}, parsed:${val})`);
    }
}
console.log(`\nTotal Penjualan > 0: ${found} dari ${rawData.length - 8} baris data`);

// Juga cek kolom lainnya
let stokKeluar = 0;
for (let i = 8; i < rawData.length; i++) {
    const row = rawData[i];
    if (!row || row.length === 0) continue;
    const raw = row[4];
    let val = 0;
    if (typeof raw === 'number') val = raw;
    else if (typeof raw === 'string') val = parseFloat(raw.replace(',', '.'));
    if (val > 0) { stokKeluar++; if (stokKeluar <= 3) console.log(`StokKeluar Row ${i}: "${row[0]}" = ${raw}`); }
}
console.log(`Stok Keluar > 0: ${stokKeluar}`);

export const dynamic = 'force-dynamic';
import { NextResponse } from 'next/server';
import { db } from '@/db';
import { inventoryState, masterBahan, masterMenu } from '@/db/schema';
import { fetchMasterData } from '@/lib/gsheets';
import { count, eq, lt, lte } from 'drizzle-orm';

export async function GET() {
    try {
        const masterData = await fetchMasterData();
        const totalProducts = masterData ? masterData.menu.length : 0;

        // We fetch SQLite inventory states to compare with bounds
        const allStock = await db.select().from(inventoryState);
        let availableStocks = 0;
        let lowStocks = 0;
        let outOfStocks = 0;

        for (const stock of allStock) {
            // Find minimum limit from Master Data
            const bahanMeta = masterData?.bahan.find(b => b.id === stock.id_bahan);
            const minLimit = bahanMeta && typeof bahanMeta.batas_minimum === 'string'
                ? parseFloat(bahanMeta.batas_minimum)
                : typeof bahanMeta?.batas_minimum === 'number'
                    ? bahanMeta.batas_minimum
                    : 0;

            availableStocks += stock.current_stock;

            if (stock.current_stock <= 0) {
                outOfStocks++;
            } else if (stock.current_stock <= minLimit) {
                lowStocks++;
            }
        }

        return NextResponse.json({
            total_products: totalProducts,
            available_stocks: availableStocks,
            low_stocks: lowStocks,
            out_of_stocks: outOfStocks
        });

    } catch (error: unknown) {
        console.error("[KPI_API] Error fetching KPI data:", error);
        return NextResponse.json({ error: 'Failed to fetch KPI' }, { status: 500 });
    }
}

export const dynamic = 'force-dynamic';
import { NextResponse } from 'next/server';
import { db } from '@/db';
import { salesReports, salesReportDetails } from '@/db/schema';
import { desc, eq } from 'drizzle-orm';

export async function GET() {
    try {
        // Fetch recent upload reports from DB
        const reports = await db.select()
            .from(salesReports)
            .orderBy(desc(salesReports.waktu_upload))
            .limit(30);

        if (reports.length === 0) {
            // Return empty array so chart shows "no data" gracefully
            return NextResponse.json([]);
        }

        // Fetch all report details and group by report_id
        const allDetails = await db.select().from(salesReportDetails);
        const detailsByReport = new Map<string, { matched: number; unmatched: number; totalQty: number }>();
        for (const d of allDetails) {
            const key = d.report_id;
            if (!detailsByReport.has(key)) {
                detailsByReport.set(key, { matched: 0, unmatched: 0, totalQty: 0 });
            }
            const entry = detailsByReport.get(key)!;
            if (d.match_status === 'matched') {
                entry.matched += d.qty_terjual;
            } else {
                entry.unmatched += d.qty_terjual;
            }
            entry.totalQty += d.qty_terjual;
        }

        const monthMap: Record<string, string> = {
            'Januari': '01', 'Februari': '02', 'Maret': '03', 'April': '04',
            'Mei': '05', 'Juni': '06', 'Juli': '07', 'Agustus': '08',
            'September': '09', 'Oktober': '10', 'November': '11', 'Desember': '12'
        };

        // Aggregate stock movements per calendar date
        const dateMap = new Map<string, { masuk: number; keluar: number; penyesuaian: number; sortKey: number }>();

        for (const r of reports) {
            if (!r.file_name) continue;

            // Try to extract date from file_name: "... - DD Bulan YYYY - ..."
            const dateMatch = r.file_name.match(/(\d{2})\s+([\w├⌐]+)\s+(\d{4})/);
            let dateKey: string;
            let sortKey: number;

            if (dateMatch) {
                const day = dateMatch[1];
                const monthName = dateMatch[2];
                const year = dateMatch[3];
                const monthNum = monthMap[monthName] || '01';
                dateKey = `${parseInt(day)} ${monthName.slice(0, 3)}`;
                sortKey = new Date(`${year}-${monthNum}-${day}`).getTime();
            } else if (r.waktu_upload) {
                const d = new Date(r.waktu_upload);
                dateKey = `${d.getDate()} ${d.toLocaleDateString('id-ID', { month: 'short' })}`;
                sortKey = d.getTime();
            } else {
                continue;
            }

            if (!dateMap.has(dateKey)) {
                dateMap.set(dateKey, { masuk: 0, keluar: 0, penyesuaian: 0, sortKey });
            }

            const entry = dateMap.get(dateKey)!;
            const details = detailsByReport.get(r.id);

            if (details) {
                entry.masuk += details.matched;
                entry.keluar += details.totalQty;
                entry.penyesuaian += details.unmatched;
            }
        }

        // Sort by actual calendar date (chronological), take last 7
        const data = Array.from(dateMap.entries())
            .map(([date, values]) => ({
                date,
                masuk: values.masuk,
                keluar: values.keluar,
                penyesuaian: values.penyesuaian,
                _sortKey: values.sortKey,
            }))
            .sort((a, b) => a._sortKey - b._sortKey)
            .map(({ _sortKey, ...rest }) => rest)
            .slice(-7);

        return NextResponse.json(data);
    } catch (error: unknown) {
        console.error("Error fetching stock movement:", error);
        return NextResponse.json({ error: 'Failed to fetch stock movement data' }, { status: 500 });
    }
}

export const dynamic = 'force-dynamic';
import { NextResponse } from 'next/server';
import { db } from '@/db';
import { salesHistory } from '@/db/schema';
import { sql, gte } from 'drizzle-orm';

export async function GET() {
    try {
        const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);

        // Group by source and day
        const srcAggregation = await db.select({
            traffic_source: salesHistory.traffic_source,
            date: sql`strftime('%Y-%m-%d', ${salesHistory.date} / 1000, 'unixepoch')`,
            total_orders: sql`SUM(${salesHistory.qty_sold})`,
        })
            .from(salesHistory)
            .where(gte(salesHistory.date, fourteenDaysAgo))
            .groupBy(salesHistory.traffic_source, sql`strftime('%Y-%m-%d', ${salesHistory.date} / 1000, 'unixepoch')`)
            .orderBy(sql`strftime('%Y-%m-%d', ${salesHistory.date} / 1000, 'unixepoch') ASC`)
            .execute();

        // Reconstruct data into the array of sparkline-friendly values per source
        const grouped: Record<string, any[]> = {};
        const totals: Record<string, number> = {};

        for (const row of srcAggregation) {
            const src = row.traffic_source || "Dine-in";
            if (!grouped[src]) {
                grouped[src] = [];
                totals[src] = 0;
            }
            grouped[src].push({ value: row.total_orders });
            totals[src] += Number(row.total_orders);
        }

        const trafficSources = Object.keys(grouped).map(source => {
            let color = "#6F767E"; // default gray
            if (source.toLowerCase().includes("go")) color = "#00AA13";
            if (source.toLowerCase().includes("grab")) color = "#00B14F";
            if (source.toLowerCase().includes("dine")) color = "#D4FF00";

            // Assume we do an arbitrary trend calculation for simplicity if not enough datapoints
            return {
                name: source,
                total: totals[source].toLocaleString(),
                trend: "+0%", // A more complex sliding win could calculate actual trend
                color: color,
                data: grouped[source].length >= 2 ? grouped[source] : Array.from({ length: 10 }).map(() => ({ value: totals[source] / 10 }))
            };
        });

        if (trafficSources.length === 0) {
            // Return blank structured format if no data
            trafficSources.push({ name: "Dine-in", total: "0", trend: "0%", color: "#D4FF00", data: Array.from({ length: 10 }).map(() => ({ value: 0 })) });
        }

        return NextResponse.json(trafficSources);

    } catch (error: unknown) {
        console.error("[TRAFFIC_API] Error:", error);
        return NextResponse.json({ error: 'Failed' }, { status: 500 });
    }
}

export const dynamic = 'force-dynamic';
import { NextResponse } from 'next/server';
import { db } from '@/db';
import { uploadBatches, inventoryLogs, salesHistory, masterBahan, masterMenu, mappingResep } from '@/db/schema';
import { sql, gte, eq, desc } from 'drizzle-orm';

export async function GET() {
    try {
        // 1. Get master data from LOCAL DB (no GSheets fetch = instant)
        const allBahan = await db.select().from(masterBahan);
        const allMenu = await db.select().from(masterMenu);
        const allResep = await db.select().from(mappingResep);

        if (allBahan.length === 0) {
            return NextResponse.json([]);
        }

        // 2. Get past 7 days sales
        const sevenDaysAgoTimestamp = Date.now() - (7 * 24 * 60 * 60 * 1000);
        const recentSales = await db.select()
            .from(salesHistory)
            .where(gte(salesHistory.date, new Date(sevenDaysAgoTimestamp)));

        // 3. Map sales to bahan usage via resep mappings
        const bahanVelocity: Record<string, number> = {};

        for (const sale of recentSales) {
            // Find resep entries for this menu
            const relatedReseps = allResep.filter((r: typeof allResep[number]) => r.menu_id === sale.id_menu);
            for (const res of relatedReseps) {
                const bahanId = res.bahan_id;
                const usage = res.jumlah_pakai * sale.qty_sold;

                if (!bahanVelocity[bahanId]) {
                    bahanVelocity[bahanId] = 0;
                }
                bahanVelocity[bahanId] += usage;
            }
        }

        // 4. Compare with current stock and calculate Days Remaining
        const upcomingRestocks = [];

        const [latestBatch] = await db.select().from(uploadBatches).orderBy(desc(uploadBatches.created_at)).limit(1);
        const allStock = latestBatch ? await db.select().from(inventoryLogs).where(eq(inventoryLogs.batch_id, latestBatch.id)) : [];

        for (const stock of allStock) {
            const bahanMeta = allBahan.find((b: typeof allBahan[number]) => b.id === stock.id_bahan);
            if (!bahanMeta) continue;

            // Skip consignment items
            if (bahanMeta.kategori_khusus === 'Consignment') continue;

            const usageLast7Days = bahanVelocity[stock.id_bahan] || 0;

            // Even if no velocity data: if stock below minimum, flag it
            if (usageLast7Days === 0) {
                if (stock.current_stock <= bahanMeta.batas_minimum) {
                    upcomingRestocks.push({
                        nama_bahan: bahanMeta.nama_bahan,
                        current_stock: stock.current_stock,
                        satuan: bahanMeta.satuan_dasar,
                        daily_velocity: "0",
                        days_remaining: stock.current_stock <= 0 ? "0" : "Γê₧",
                        batas_minimum: bahanMeta.batas_minimum,
                        vendor_id: bahanMeta.vendor_id,
                    });
                }
                continue;
            }

            const dailyVelocity = usageLast7Days / 7;
            const daysRemaining = stock.current_stock / dailyVelocity;

            // Show items that will run out within 5 days or below minimum
            if (daysRemaining <= 5 || stock.current_stock <= bahanMeta.batas_minimum) {
                upcomingRestocks.push({
                    nama_bahan: bahanMeta.nama_bahan,
                    current_stock: stock.current_stock,
                    satuan: bahanMeta.satuan_dasar,
                    daily_velocity: dailyVelocity.toFixed(2),
                    days_remaining: daysRemaining.toFixed(1),
                    batas_minimum: bahanMeta.batas_minimum,
                    vendor_id: bahanMeta.vendor_id,
                });
            }
        }

        // Sort by most urgent
        upcomingRestocks.sort((a, b) => {
            const daysA = a.days_remaining === 'Γê₧' ? 999 : parseFloat(a.days_remaining);
            const daysB = b.days_remaining === 'Γê₧' ? 999 : parseFloat(b.days_remaining);
            return daysA - daysB;
        });

        return NextResponse.json(upcomingRestocks);

    } catch (error: unknown) {
        console.error("[RESTOCK_API] Error predicting restock:", error);
        return NextResponse.json({ error: 'Failed' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { db } from '@/db';
import { inventoryState, masterBahan, masterVendor } from '@/db/schema';
import { eq } from 'drizzle-orm';
import { fetchMasterData } from '@/lib/gsheets';

interface StockRow {
    id_bahan: string;
    current_stock: number;
    last_updated: Date | null;
    nama_bahan: string | null;
    satuan_dasar: string | null;
    batas_minimum: number | null;
    vendor_id: string | null;
    vendor_nama: string | null;
}

export const dynamic = 'force-dynamic';

export async function GET() {
    try {
        // 1. Ambil semua stok dari INVENTORY_STATE (join ke MASTER_BAHAN & MASTER_VENDOR)
        const stockData = await db
            .select({
                id_bahan: inventoryState.id_bahan,
                current_stock: inventoryState.current_stock,
                last_updated: inventoryState.last_updated,
                nama_bahan: masterBahan.nama_bahan,
                satuan_dasar: masterBahan.satuan_dasar,
                batas_minimum: masterBahan.batas_minimum,
                vendor_id: masterBahan.vendor_id,
                vendor_nama: masterVendor.nama_vendor,
            })
            .from(inventoryState)
            .leftJoin(masterBahan, eq(inventoryState.id_bahan, masterBahan.id))
            .leftJoin(masterVendor, eq(masterBahan.vendor_id, masterVendor.id));

        // 2. Ambil Master Data dari GSheets untuk info Harga_Beli dan Minimal_Stock
        const masterData = await fetchMasterData();
        const bahanMap = new Map<string, Record<string, string | null | undefined>>();
        if (masterData?.bahan) {
            for (const b of masterData.bahan) {
                const record = b as Record<string, unknown>;
                if (typeof record.id_bahan === 'string') {
                    bahanMap.set(record.id_bahan, record as Record<string, string | null | undefined>);
                }
            }
        }

        // 3. Hitung prediksi untuk setiap item
        const result = stockData.map(item => {
            const gsheetsBahan = bahanMap.get(item.id_bahan);
            const minStock = item.batas_minimum || parseFloat(gsheetsBahan?.Minimal_Stock || "0");
            const currentStock = item.current_stock || 0;

            // Stok akhir (current) sudah merepresentasikan stok hari ini setelah pemotongan
            // Prediksi PO: jika stok di bawah minimum, hitung berapa yang perlu dipesan
            const needsRestock = currentStock <= minStock;
            const suggestedOrderQty = needsRestock ? Math.max(minStock * 2 - currentStock, minStock) : 0;

            let stockStatus = 'sufficient';
            if (currentStock <= 0) stockStatus = 'out';
            else if (currentStock <= minStock) stockStatus = 'low';
            else if (currentStock <= minStock * 1.5) stockStatus = 'warning';

            return {
                id_bahan: item.id_bahan,
                nama_bahan: item.nama_bahan || gsheetsBahan?.nama_bahan || '---',
                satuan: item.satuan_dasar || gsheetsBahan?.satuan_dasar || 'Pcs',
                current_stock: currentStock,
                batas_minimum: minStock,
                vendor_nama: item.vendor_nama || 'N/A',
                vendor_id: item.vendor_id || '',
                stock_status: stockStatus,
                needs_restock: needsRestock,
                suggested_order_qty: Math.round(suggestedOrderQty),
                last_updated: item.last_updated,
            };
        });

        // Sort: Out > Low > Warning > Sufficient
        const statusOrder: Record<string, number> = { out: 0, low: 1, warning: 2, sufficient: 3 };
        result.sort((a, b) => statusOrder[a.stock_status] - statusOrder[b.stock_status]);

        return NextResponse.json(result);
    } catch (error: unknown) {
        console.error("[SMART-STOCK] Error:", error);
        return NextResponse.json({ error: 'Failed to compute smart stock' }, { status: 500 });
    }
}

export const dynamic = 'force-dynamic';
// @ts-nocheck
import { NextResponse } from 'next/server';
import Imap from 'node-imap';
import { simpleParser } from 'mailparser';
import * as xlsx from 'xlsx';
import { matchKartuStok } from '@/lib/engine';

export async function POST(req: Request): Promise<NextResponse> {
    const imapConfig = {
        user: process.env.IMAP_USER || '',
        password: process.env.IMAP_PASSWORD || '',
        host: process.env.IMAP_HOST || 'imap.gmail.com',
        port: parseInt(process.env.IMAP_PORT || '993'),
        tls: true,
        tlsOptions: { rejectUnauthorized: false }
    };

    if (!imapConfig.user || !imapConfig.password) {
        return NextResponse.json({ error: 'IMAP configuration missing' }, { status: 500 });
    }

    return new Promise<NextResponse>((resolve) => {
        const imap = new Imap(imapConfig);

        imap.once('ready', () => {
            imap.openBox('INBOX', false, (err, box) => {
                if (err) {
                    imap.end();
                    return resolve(NextResponse.json({ error: 'Error opening inbox' }, { status: 500 }));
                }

                // Search for unread emails with Pawoon attachment
                imap.search(['UNSEEN', ['SUBJECT', 'Pawoon Sales Report']], (err, results) => {
                    if (err || !results || results.length === 0) {
                        imap.end();
                        return resolve(NextResponse.json({ message: 'No new Pawoon reports found' }));
                    }

                    const fetch = imap.fetch(results, { bodies: '' });

                    fetch.on('message', (msg) => {
                        msg.on('body', (stream) => {
                            simpleParser(stream as any, async (err, parsed) => {
                                if (err) return;

                                const attachment = parsed.attachments.find(a => a.filename?.endsWith('.xls') || a.filename?.endsWith('.xlsx'));

                                if (attachment) {
                                    try {
                                        const workbook = xlsx.read(attachment.content, { type: 'buffer' });
                                        const sheetName = workbook.SheetNames[0];
                                        const sheet = workbook.Sheets[sheetName];

                                        const rawData = xlsx.utils.sheet_to_json(sheet, { header: 1 });
                                        const actualDataRows = rawData.slice(7); // Skip 7 rows

                                        const parsedSales = actualDataRows.map((row: unknown) => {
                                            const r = row as string[];
                                            return {
                                                nama_menu: r[0] || "Unknown",
                                                qty_sold: parseInt(r[4] || "0", 10),
                                                harga_jual: parseFloat(r[5] || "0"),
                                                traffic_source: r[8] || "Dine-in"
                                            };
                                        }).filter(r => r.qty_sold > 0);

                                        // Mark as read and process (ephemeral, no DB writes)
                                        const mappedForEngine = parsedSales.map(s => ({
                                            nama_bahan: s.nama_menu,
                                            stok_awal: 0,
                                            stok_masuk: 0,
                                            stok_keluar: 0,
                                            penjualan: s.qty_sold,
                                            stok_akhir: 0,
                                            satuan: "",
                                            kategori: ""
                                        }));
                                        await matchKartuStok(mappedForEngine, "Auto-Email System");
                                    } catch (e: unknown) {
                                        console.error("[IMAP] Error parsing or processing attached Excel:", e);
                                    }
                                }
                            });
                        });

                        // Mark email as SEEN
                        msg.once('attributes', (attrs) => {
                            imap.addFlags(attrs.uid, ['\\Seen'], (err) => {
                                if (err) console.error("Could not mark as seen", err);
                            });
                        });
                    });

                    fetch.once('end', () => {
                        imap.end();
                        resolve(NextResponse.json({ success: true, message: 'Processed latest Pawoon reports' }));
                    });
                });
            });
        });

        imap.once('error', (err: unknown) => {
            console.error("[IMAP] connection error", err);
            resolve(NextResponse.json({ error: 'IMAP Connection Error' }, { status: 500 }));
        });

        imap.connect();
    });
}

export const dynamic = 'force-dynamic';
import { NextResponse } from "next/server";
import { db } from "@/db";
import { masterMenu, masterBahan } from "@/db/schema";
import { like, or } from "drizzle-orm";

export async function GET(request: Request) {
    const { searchParams } = new URL(request.url);
    const query = searchParams.get('q');

    if (!query) {
        return NextResponse.json([]);
    }

    try {
        const lowerQuery = query.toLowerCase();
        const results = [];

        // Mock Smart Query logic for "stok keluar hari ini"
        if (lowerQuery.includes('stok keluar') || lowerQuery.includes('hari ini')) {
            results.push({
                id: 'smart-1',
                title: 'Laporan Stok Keluar Hari Ini',
                description: 'Lihat ringkasan stok keluar dari semua outlet',
                type: 'report',
                url: '/dashboard'
            });
        }

        // Search Master Menu
        const menus = await db.select().from(masterMenu)
            .where(like(masterMenu.nama_menu, `%${query}%`))
            .limit(3);

        for (const menu of menus) {
            results.push({
                id: `menu-${menu.id}`,
                title: menu.nama_menu,
                description: `Menu Outlet ${menu.outlet_id}`,
                type: 'product',
                url: '/products'
            });
        }

        // Search Master Bahan
        const bahans = await db.select().from(masterBahan)
            .where(like(masterBahan.nama_bahan, `%${query}%`))
            .limit(3);

        for (const bahan of bahans) {
            results.push({
                id: `bahan-${bahan.id}`,
                title: bahan.nama_bahan,
                description: `Batas Minimum: ${bahan.batas_minimum} ${bahan.satuan_dasar}`,
                type: 'product',
                url: '/products'
            });
        }

        // Add a mock order/store search logic if needed
        if (lowerQuery.includes('mas ahmad')) {
            results.push({
                id: 'supplier-1',
                title: 'Vendor: Mas Ahmad',
                description: 'Supplier Sayur & Bumbu',
                type: 'store',
