                            </Table>
                        </div>
                    ) : (
                        <div className="text-sm text-slate-500 flex h-24 items-center justify-center border rounded-md border-dashed">
                            Belum ada data inventori.
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    )
}

"use client";

import { useState, useRef } from "react";
import { UploadCloud, FileSpreadsheet, X, CheckCircle2, AlertCircle, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { useInventoryStore } from "@/lib/store/useInventoryStore";

export function DropzoneUploader() {
    const [isDragging, setIsDragging] = useState(false);
    const [file, setFile] = useState<File | null>(null);
    const [isUploading, setIsUploading] = useState(false);
    const [uploadStatus, setUploadStatus] = useState<"idle" | "success" | "error">("idle");
    const [statusMessage, setStatusMessage] = useState("");

    const fileInputRef = useRef<HTMLInputElement>(null);
    const { setInventoryData } = useInventoryStore();

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(true);
    };

    const handleDragLeave = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);
    };

    const validateFile = (selectedFile: File) => {
        // Pawoon legacy format (.xls) verification
        const validTypes = [
            "application/vnd.ms-excel",
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet", // Also accept modern xlsx just in case
        ];

        if (!validTypes.includes(selectedFile.type) && !selectedFile.name.endsWith('.xls') && !selectedFile.name.endsWith('.xlsx')) {
            toast.error("Invalid File Format", {
                description: "Only Excel files (.xls, .xlsx) from Pawoon are supported.",
            });
            return false;
        }
        return true;
    };

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setIsDragging(false);

        const droppedFiles = Array.from(e.dataTransfer.files);
        if (droppedFiles.length > 0) {
            const selectedFile = droppedFiles[0];
            if (validateFile(selectedFile)) {
                setFile(selectedFile);
                setUploadStatus("idle");
            }
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFiles = e.target.files;
        if (selectedFiles && selectedFiles.length > 0) {
            const selectedFile = selectedFiles[0];
            if (validateFile(selectedFile)) {
                setFile(selectedFile);
                setUploadStatus("idle");
            }
        }
    };

    const handleRemoveFile = () => {
        setFile(null);
        setUploadStatus("idle");
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleUpload = async () => {
        if (!file) return;

        setIsUploading(true);
        setUploadStatus("idle");

        const formData = new FormData();
        formData.append("file", file);

        try {
            const response = await fetch("/api/sales/upload", {
                method: "POST",
                body: formData,
            });

            const result = await response.json();

            if (response.ok && result.success) {
                setUploadStatus("success");
                setStatusMessage(`Berhasil memproses ${result.matchedCount} / ${result.matchedCount + result.unmatchedCount} item dari ${result.outlet}.`);

                // Store matched inventory data in Zustand (client-side only, ephemeral)
                if (result.matchedItems && result.matchedItems.length > 0) {
                    setInventoryData(result.matchedItems, result.outlet ?? '');
                }

                toast.success("Upload Berhasil!", {
                    description: result.message,
                });

                // Reset uploader after 3s
                setTimeout(() => handleRemoveFile(), 3000);
            } else {
                setUploadStatus("error");
                setStatusMessage(result.error || "Failed to process the uploaded file.");
                toast.error("Upload Failed", {
                    description: result.error || "An error occurred during file processing.",
                });
            }
        } catch (error) {
            setUploadStatus("error");
            setStatusMessage("Network error or server unavailable.");
            toast.error("Network Error", {
                description: "Failed to communicate with the server.",
            });
        } finally {
            setIsUploading(false);
        }
    };

    return (
        <div className="w-full bg-card border border-border rounded-2xl p-6 shadow-sm">
            <div className="flex flex-col gap-2 mb-6">
                <h2 className="text-lg font-bold text-foreground flex items-center gap-2">
                    <UploadCloud className="w-5 h-5 text-primary" />
                    Smart Batch Uploader
                </h2>
                <p className="text-sm text-secondary-foreground">
                    Upload your Legacy Pawoon Sales Report (<b>.xls</b>) here. The engine will automatically parse rows, match menus, and deduct actual inventory stocks instantly.
                </p>
            </div>

            {!file ? (
                <div
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                    onClick={() => fileInputRef.current?.click()}
                    className={cn(
                        "flex flex-col items-center justify-center w-full h-48 border-2 border-dashed rounded-xl cursor-pointer transition-all duration-200",
                        isDragging
                            ? "border-primary bg-primary/5 scale-[1.01]"
                            : "border-border hover:border-primary/50 hover:bg-secondary/30 bg-secondary/10"
                    )}
                >
                    <div className="flex flex-col items-center justify-center pt-5 pb-6 gap-3">
                        <div className={cn(
                            "p-3 rounded-full transition-colors",
                            isDragging ? "bg-primary text-primary-foreground" : "bg-card border border-border text-muted-foreground"
                        )}>
                            <UploadCloud className="w-6 h-6" />
                        </div>
                        <div className="text-center">
                            <p className="text-sm font-semibold text-foreground">
                                Click to upload <span className="font-normal text-muted-foreground">or drag and drop</span>
                            </p>
                            <p className="text-xs text-muted-foreground mt-1">Excel 97-2003 Legacy (.xls) supported</p>
                        </div>
                    </div>
                    <input
                        type="file"
                        ref={fileInputRef}
                        className="hidden"
                        accept=".xls,.xlsx,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
                        onChange={handleFileChange}
                    />
                </div>
            ) : (
                <div className="flex flex-col gap-4">
                    <div className={cn(
                        "flex items-center justify-between p-4 border rounded-xl bg-secondary/20",
                        uploadStatus === "success" && "border-green-500/50 bg-green-500/10",
                        uploadStatus === "error" && "border-destructive/50 bg-destructive/10"
                    )}>
                        <div className="flex items-center gap-4">
                            <div className={cn(
                                "p-2 rounded-lg",
                                uploadStatus === "success" ? "bg-green-500/20 text-green-500" :
                                    uploadStatus === "error" ? "bg-destructive/20 text-destructive" :
                                        "bg-primary/20 text-primary"
                            )}>
                                {uploadStatus === "success" ? <CheckCircle2 className="w-5 h-5" /> :
                                    uploadStatus === "error" ? <AlertCircle className="w-5 h-5" /> :
                                        <FileSpreadsheet className="w-5 h-5" />}
                            </div>
                            <div className="flex flex-col">
                                <span className="text-sm font-semibold text-foreground truncate max-w-[200px] sm:max-w-xs">{file.name}</span>
                                <span className="text-xs text-muted-foreground">{(file.size / 1024).toFixed(1)} KB</span>
                            </div>
                        </div>

                        {!isUploading && uploadStatus !== "success" && (
                            <Button variant="ghost" size="icon" onClick={handleRemoveFile} className="text-muted-foreground hover:text-destructive shrink-0">
                                <X className="w-4 h-4" />
                            </Button>
                        )}
                    </div>

                    {statusMessage && (
                        <p className={cn(
                            "text-sm font-medium",
                            uploadStatus === "success" ? "text-green-500" : "text-destructive"
                        )}>
                            {statusMessage}
                        </p>
                    )}

                    {!isUploading && uploadStatus !== "success" && (
                        <div className="flex gap-3 justify-end mt-2">
                            <Button variant="outline" onClick={handleRemoveFile} disabled={isUploading}>
                                Cancel
                            </Button>
                            <Button onClick={handleUpload} disabled={isUploading} className="min-w-[120px]">
                                Parse & Evaluate
                            </Button>
                        </div>
                    )}

                    {isUploading && (
                        <div className="flex items-center justify-center gap-2 p-2 mt-2 text-sm font-medium text-muted-foreground">
                            <Loader2 className="w-4 h-4 animate-spin text-primary" />
                            Evaluating Inventory & Extracting Pawoon Rows...
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}

"use client";

import { useRef } from "react";
import { useReactToPrint } from "react-to-print";
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Trash2, Copy, FileText, ShoppingCart, MessageCircle } from "lucide-react";
import { toast } from "sonner";
import { usePOBuilder, POItem } from "@/lib/store/usePOBuilder";
import { saveInvoiceDrafts } from "@/app/actions/invoice";
import { useState } from "react";
import { useSession } from "next-auth/react";

export function InvoiceGenerator() {
    const { approvedPOs, clearPOs, removePO } = usePOBuilder();
    const printRef = useRef<HTMLDivElement>(null);
    const [isSaving, setIsSaving] = useState(false);
    const { data: session } = useSession();
    const username = (session?.user as { username?: string })?.username || "Staf OMNI";

    const handlePrint = useReactToPrint({
        contentRef: printRef,
        documentTitle: `PO_Invoice_${new Date().toISOString().split('T')[0]}`,
        onAfterPrint: () => {
            toast.success("PDF berhasil dicetak");
            clearPOs(); // Automatically clear after saving and printing
        },
    });

    // Group items by Vendor
    const groupedPOs = approvedPOs.reduce((acc, item) => {
        if (!acc[item.vendor_nama]) acc[item.vendor_nama] = [];
        acc[item.vendor_nama].push(item);
        return acc;
    }, {} as Record<string, POItem[]>);

    const grandTotal = approvedPOs.reduce((sum, item) => sum + (item.qty * (item.harga_satuan || 0)), 0);

    const handleCopyText = (vendorName: string, items: POItem[]) => {
        let text = `*DRAFT PO - ${vendorName}*\nTanggal: ${new Date().toLocaleDateString('id-ID')}\n\n`;
        let total = 0;

        items.forEach((item, idx) => {
            const subtotal = item.qty * (item.harga_satuan || 0);
            total += subtotal;
            text += `${idx + 1}. ${item.nama_bahan}\n   ${item.qty} x Rp ${(item.harga_satuan || 0).toLocaleString('id-ID')} = Rp ${subtotal.toLocaleString('id-ID')}\n`;
        });

        text += `\n*Total Estimasi: Rp ${total.toLocaleString('id-ID')}*`;
        const paymentInfo = items.find(i => i.info_pembayaran)?.info_pembayaran;
        if (paymentInfo) {
            text += `\n\nInfo Pembayaran Vendor:\n${paymentInfo}`;
        }

        // PRD V5.5: Audit Trail Stamp
        text += `\n\nDisiapkan oleh: ${username}`;

        navigator.clipboard.writeText(text);
        toast.success("Teks disalin ke Clipboard!", { description: `Format WA untuk vendor ${vendorName} siap dikirim.` });
    };

    const handleExportAndSave = async () => {
        setIsSaving(true);
        try {
            const res = await saveInvoiceDrafts(groupedPOs);
            if (res.success) {
                toast.success("Invoice berhasil disimpan ke Arsip!");
                handlePrint();
            } else {
                toast.error("Gagal menyimpan Invoice ke Database", { description: res.error });
            }
        } catch (err: unknown) {
            toast.error("Error Sistem", { description: err instanceof Error ? err.message : "Terjadi kesalahan" });
        } finally {
            setIsSaving(false);
        }
    };

    if (approvedPOs.length === 0) {
        return (
            <Card className="h-full border-white/10 flex flex-col items-center justify-center p-8 text-center bg-secondary/10">
                <div className="h-16 w-16 bg-secondary/50 rounded-full flex items-center justify-center mb-4">
                    <ShoppingCart className="h-8 w-8 text-muted-foreground opacity-50" />
                </div>
                <h3 className="text-lg font-semibold text-muted-foreground">Keranjang PO Kosong</h3>
                <p className="text-sm text-muted-foreground mt-2 max-w-[250px]">
                    Klik tombol &quot;Rancang PO&quot; pada tabel inventory untuk mulai menyusun PO dan Invoice.
                </p>
            </Card>
        );
    }

    return (
        <Card className="h-full border-white/10 flex flex-col shadow-xl">
            <CardHeader className="bg-lime-500/10 border-b border-lime-500/20 pb-4">
                <CardTitle className="text-lg flex justify-between items-center text-lime-600 dark:text-lime-400">
                    <span className="flex items-center gap-2"><FileText className="h-5 w-5" /> Draft Invoices</span>
                    <Badge variant="outline" className="border-lime-500/50 bg-lime-500/10">{approvedPOs.length} Items</Badge>
                </CardTitle>
            </CardHeader>

            <CardContent className="flex-1 overflow-y-auto p-0" ref={printRef}>
                <div className="p-4 sm:p-6 space-y-6">
                    {/* Header for PDF printing only */}
                    <div className="hidden print:block text-center border-b pb-4 mb-6">
                        <h1 className="text-2xl font-bold">PURCHASE ORDER INVOICE</h1>
                        <p className="text-sm text-gray-500">Divisi Logistik & Inventory</p>
                        <p className="text-sm">Tanggal: {new Date().toLocaleDateString('id-ID')}</p>
                    </div>

                    {Object.entries(groupedPOs).map(([vendor, items]) => {
                        const vendorTotal = items.reduce((sum, item) => sum + (item.qty * (item.harga_satuan || 0)), 0);
                        const paymentInfo = items.find(i => i.info_pembayaran)?.info_pembayaran;

                        return (
                            <div key={vendor} className="bg-secondary/20 rounded-xl p-4 border border-border">
                                <div className="flex justify-between items-start mb-3">
                                    <h4 className="font-bold text-foreground">{vendor}</h4>
                                    <Button variant="ghost" size="sm" className="h-7 text-xs text-blue-500 hover:text-blue-400 print:hidden" onClick={() => handleCopyText(vendor, items)}>
                                        <MessageCircle className="h-3.5 w-3.5 mr-1" /> WA Text
                                    </Button>
                                </div>
                                <div className="space-y-3">
                                    {items.map((item) => (
                                        <div key={item.id_bahan} className="flex justify-between items-center group">
                                            <div>
                                                <p className="text-sm font-medium">{item.nama_bahan}</p>
                                                <div className="flex items-center gap-2 text-xs text-muted-foreground mt-0.5">
                                                    <span>{item.qty} x Rp {(item.harga_satuan || 0).toLocaleString('id-ID')}</span>
                                                    <Button variant="ghost" size="icon" className="h-5 w-5 opacity-0 group-hover:opacity-100 transition-opacity print:hidden text-destructive" onClick={() => removePO(item.id_bahan)}>
                                                        <Trash2 className="h-3 w-3" />
                                                    </Button>
                                                </div>
                                            </div>
                                            <p className="font-semibold text-sm">
                                                Rp {(item.qty * (item.harga_satuan || 0)).toLocaleString('id-ID')}
                                            </p>
                                        </div>
                                    ))}
                                </div>
                                <hr className="my-3 opacity-50 border-border" />
                                <div className="flex justify-between items-center text-sm">
                                    <span className="text-muted-foreground font-medium">Subtotal Vendor:</span>
                                    <span className="font-bold text-amber-600 dark:text-amber-500">Rp {vendorTotal.toLocaleString('id-ID')}</span>
                                </div>
                                {paymentInfo && (
                                    <div className="mt-3 p-2 bg-muted/50 rounded text-xs">
                                        <span className="font-semibold block mb-0.5 text-muted-foreground">Pembayaran:</span>
                                        {paymentInfo}
                                    </div>
                                )}
                            </div>
                        );
                    })}

                    {/* Footer for PDF printing only - PRD V5.5 Audit Trail Stamp */}
                    <div className="hidden print:flex justify-end mt-12 mb-4">
                        <div className="text-center">
                            <p className="text-sm mb-16">Disiapkan Oleh,</p>
                            <p className="text-sm font-bold underline decoration-2 underline-offset-4">{username}</p>
                            <p className="text-xs text-muted-foreground mt-1">Gudang / Pembelian</p>
                        </div>
                    </div>
                </div>
            </CardContent>

            <hr className="border-border" />

            <CardFooter className="flex-col gap-4 p-4 sm:p-6 bg-secondary/10 print:hidden">
                <div className="flex justify-between items-center w-full">
                    <span className="font-semibold text-muted-foreground">Grand Total Estimasi</span>
                    <span className="text-2xl font-bold">Rp {grandTotal.toLocaleString('id-ID')}</span>
                </div>
                <div className="grid grid-cols-2 gap-3 w-full">
                    <Button variant="outline" className="text-destructive hover:bg-destructive/10" onClick={clearPOs} disabled={isSaving}>
                        <Trash2 className="h-4 w-4 mr-2" /> Kosongkan
                    </Button>
                    <Button className="bg-lime-500 text-black hover:bg-lime-600 shadow-md shadow-lime-500/20" onClick={handleExportAndSave} disabled={isSaving}>
                        <FileText className="h-4 w-4 mr-2" /> {isSaving ? "Menyimpan..." : "Export PDF & Simpan"}
                    </Button>
                </div>
            </CardFooter>
        </Card>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";

export function OrderSummaryChart() {
    const [data, setData] = useState<any[]>([]);

    useEffect(() => {
        async function fetchOrderSummary() {
            try {
                const res = await fetch("/api/dashboard/order-summary?days=7");
                if (res.ok) {
                    const rawData = await res.json();
                    const formatted = rawData.map((d: any) => ({
                        name: d.date.split('-').slice(1).join('/'), // Convert YYYY-MM-DD to MM/DD
                        orders: d.total_orders
                    }));
                    setData(formatted);
                }
            } catch (error) {
                console.error("Failed to fetch order summary", error);
            }
        }
        fetchOrderSummary();
    }, []);

    return (
        <Card className="h-full border-white/10 dark:border-white/5">
            <CardHeader>
                <div className="flex justify-between items-center">
                    <div>
                        <CardTitle className="text-lg">Order Summary</CardTitle>
                        <CardDescription>Weekly order performance</CardDescription>
                    </div>
                    <select className="bg-secondary/50 text-sm rounded-lg px-2 py-1 text-secondary-foreground border-none outline-none focus:ring-1 focus:ring-primary">
                        <option>This Week</option>
                        <option>Last Week</option>
                    </select>
                </div>
            </CardHeader>
            <CardContent>
                <div className="h-[280px] w-full mt-4">
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                            <defs>
                                <linearGradient id="colorOrders" x1="0" y1="0" x2="0" y2="1">
                                    <stop offset="5%" stopColor="#D4FF00" stopOpacity={0.3} />
                                    <stop offset="95%" stopColor="#D4FF00" stopOpacity={0} />
                                </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />
                            <XAxis
                                dataKey="name"
                                axisLine={false}
                                tickLine={false}
                                tick={{ fontSize: 12, fill: "hsl(var(--muted-foreground))" }}
                                dy={10}
                            />
                            <YAxis
                                axisLine={false}
                                tickLine={false}
                                tick={{ fontSize: 12, fill: "hsl(var(--muted-foreground))" }}
                            />
                            <Tooltip
                                contentStyle={{
                                    backgroundColor: "hsl(var(--card))",
                                    borderRadius: "8px",
                                    border: "1px solid hsl(var(--border))",
                                    fontWeight: 500,
                                    color: "hsl(var(--foreground))"
                                }}
                                itemStyle={{ color: "hsl(var(--foreground))" }}
                            />
                            <Area
                                type="monotone"
                                dataKey="orders"
                                stroke="#D4FF00"
                                strokeWidth={3}
                                fillOpacity={1}
                                fill="url(#colorOrders)"
                            />
                        </AreaChart>
                    </ResponsiveContainer>
                </div>
            </CardContent>
        </Card>
    );
}

