"use client";

import { useEffect, useState } from "react";
import { Trash2, UserPlus, Shield, Mail, User } from "lucide-react";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";

interface UserResponse {
    id: string;
    email: string;
    username: string;
    role: string;
    created_at: string;
}

export function UserManagementTable({ currentUser }: { currentUser: any }) {
    const [users, setUsers] = useState<UserResponse[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [open, setOpen] = useState(false);

    // Form State
    const [email, setEmail] = useState("");
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [role, setRole] = useState("STAFF");

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const res = await fetch("/api/users");
            if (res.ok) {
                const data = await res.json();
                setUsers(data);
            } else {
                toast.error("Gagal mengambil data pengguna");
            }
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, []);

    const handleCreateUser = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        try {
            const res = await fetch("/api/users/create", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ email, username, password, role }),
            });
            const data = await res.json();

            if (res.ok) {
                toast.success(data.message);
                setOpen(false);
                fetchUsers(); // Refresh table
                // Reset form
                setEmail("");
                setUsername("");
                setPassword("");
                setRole("STAFF");
            } else {
                toast.error(data.error || "Gagal membuat pengguna");
            }
        } catch (error) {
            toast.error("Terjadi kesalahan sistem");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDeleteUser = async (id: string) => {
        if (!confirm("Apakah Anda yakin ingin menghapus pengguna ini?")) return;

        try {
            const res = await fetch(`/api/users?id=${id}`, { method: "DELETE" });
            const data = await res.json();

            if (res.ok) {
                toast.success(data.message);
                fetchUsers();
            } else {
                toast.error(data.error);
            }
        } catch (error) {
            toast.error("Terjadi kesalahan saat menghapus pengguna");
        }
    };

    const roleColor: Record<string, string> = {
        MANAGER: "bg-violet-500/15 text-violet-600 dark:text-violet-400 border-violet-500/20",
        SPV: "bg-blue-500/15 text-blue-600 dark:text-blue-400 border-blue-500/20",
        STAFF: "bg-slate-500/15 text-slate-600 dark:text-slate-400 border-slate-500/20",
    };

    return (
        <Card className="border-border shadow-sm">
            <CardHeader className="flex flex-row items-center justify-between pb-4">
                <div>
                    <CardTitle>Daftar Akun OMNI-STOCK</CardTitle>
                    <CardDescription>Semua staf, supervisor, dan manajer yang terdaftar.</CardDescription>
                </div>
                <Dialog open={open} onOpenChange={setOpen}>
                    <DialogTrigger asChild>
                        <Button className="bg-primary text-primary-foreground">
                            <UserPlus className="h-4 w-4 mr-2" />
                            Tambah Pengguna
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[425px]">
                        <DialogHeader>
                            <DialogTitle>Tambah Pengguna Baru</DialogTitle>
                            <DialogDescription>
                                Buat kredensial akun untuk staf. Password akan di-hash dan tidak dapat dilihat.
                            </DialogDescription>
                        </DialogHeader>
                        <form onSubmit={handleCreateUser} className="space-y-4 py-4">
                            <div className="space-y-2">
                                <Label htmlFor="email">Email Login</Label>
                                <div className="relative">
                                    <Mail className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                                    <Input
                                        id="email"
                                        type="email"
                                        required
                                        className="pl-9"
                                        placeholder="nama@omni.com"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                    />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="username">Username (Tampilan)</Label>
                                <div className="relative">
                                    <User className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                                    <Input
                                        id="username"
                                        required
                                        className="pl-9"
                                        placeholder="Nama Lengkap / Singkat"
                                        value={username}
                                        onChange={(e) => setUsername(e.target.value)}
                                    />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="password">Password Default</Label>
                                <Input
                                    id="password"
                                    type="password"
                                    required
                                    placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                />
                                <p className="text-[10px] text-muted-foreground leading-tight">Berikan password ini ke staf, sarankan untuk menggantinya nanti.</p>
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="role">Hak Akses (Role)</Label>
                                <Select value={role} onValueChange={setRole}>
                                    <SelectTrigger>
                                        <SelectValue placeholder="Pilih Role" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="STAFF">STAFF (Inventory, PO, Produksi)</SelectItem>
                                        <SelectItem value="SPV">SPV (Approve PO, Void)</SelectItem>
                                        <SelectItem value="MANAGER">MANAGER (All + User Management)</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <DialogFooter className="pt-4">
                                <Button type="submit" disabled={isSubmitting} className="w-full">
                                    {isSubmitting ? "Menyimpan..." : "Buat Akun"}
                                </Button>
                            </DialogFooter>
                        </form>
                    </DialogContent>
                </Dialog>
            </CardHeader>
            <CardContent>
                <div className="rounded-md border border-border">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-muted text-muted-foreground text-xs uppercase font-medium">
                            <tr>
                                <th className="px-4 py-3">Username / Email</th>
                                <th className="px-4 py-3">Role</th>
                                <th className="px-4 py-3">Terdaftar Sejak</th>
                                <th className="px-4 py-3 text-right">Aksi</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {loading ? (
                                <tr>
                                    <td colSpan={4} className="h-24 text-center text-muted-foreground">Memuat data...</td>
                                </tr>
                            ) : users.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="h-24 text-center text-muted-foreground">Tidak ada pengguna ditemukan.</td>
                                </tr>
                            ) : (
                                users.map((user) => (
                                    <tr key={user.id} className="hover:bg-muted/50 transition-colors">
                                        <td className="px-4 py-3">
                                            <div className="font-semibold text-foreground flex items-center gap-2">
                                                {user.username}
                                                {user.id === currentUser.id && (
                                                    <span className="text-[9px] bg-primary/10 text-primary px-1.5 py-0.5 rounded uppercase tracking-wider">Anda</span>
                                                )}
                                            </div>
                                            <div className="text-xs text-muted-foreground mt-0.5">{user.email}</div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <Badge variant="outline" className={`text-[10px] font-bold ${roleColor[user.role] || roleColor.STAFF}`}>
                                                {user.role === 'MANAGER' && <Shield className="h-3 w-3 mr-1" />}
                                                {user.role}
                                            </Badge>
                                        </td>
                                        <td className="px-4 py-3 text-muted-foreground text-xs">
                                            {new Date(user.created_at).toLocaleDateString("id-ID", { day: 'numeric', month: 'short', year: 'numeric' })}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <Button
                                                variant="ghost"
                                                size="icon"
                                                className="h-8 w-8 text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                                                onClick={() => handleDeleteUser(user.id)}
                                                disabled={user.id === currentUser.id}
                                                title={user.id === currentUser.id ? "Tidak dapat menghapus akun sendiri" : "Hapus Pengguna"}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { usePathname } from "next/navigation";
import { SessionProvider } from "next-auth/react";
import { Sidebar } from "./Sidebar";
import { Header } from "./Header";
import { cn } from "@/lib/utils";

export function AppShell({ children }: { children: React.ReactNode }) {
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [isMobile, setIsMobile] = useState(false);
    const pathname = usePathname();

    // Detect mobile
    useEffect(() => {
        const checkMobile = () => {
            const mobile = window.innerWidth < 768;
            setIsMobile(mobile);
            if (mobile) setIsSidebarOpen(false);
            else setIsSidebarOpen(true);
        };
        checkMobile();
        window.addEventListener("resize", checkMobile);
        return () => window.removeEventListener("resize", checkMobile);
    }, []);

    // Auto-close sidebar on mobile when navigating
    useEffect(() => {
        if (isMobile) setIsSidebarOpen(false);
    }, [pathname, isMobile]);

    return (
        // SessionProvider wraps the entire shell so useSession() works in Header & all children
        <SessionProvider>
            <div className="h-screen w-full bg-background overflow-hidden">
                {/* Mobile overlay backdrop */}
                {isMobile && isSidebarOpen && (
                    <div
                        className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40 transition-opacity"
                        onClick={() => setIsSidebarOpen(false)}
                    />
                )}

                {/* Sidebar */}
                <aside
                    className={cn(
                        "fixed top-0 left-0 h-full z-50 bg-sidebar border-r border-border transition-all duration-300",
                        isMobile
                            ? (isSidebarOpen ? "w-[260px] translate-x-0" : "w-[260px] -translate-x-full")
                            : (isSidebarOpen ? "w-[260px]" : "w-[80px]")
                    )}
                >
                    <Sidebar isOpen={isSidebarOpen || isMobile} toggle={() => setIsSidebarOpen(!isSidebarOpen)} />
                </aside>

                {/* Main content ΓÇö offset by sidebar width on desktop */}
                <div
                    className={cn(
                        "flex flex-col h-full transition-all duration-300",
                        isMobile
                            ? "ml-0"
                            : (isSidebarOpen ? "ml-[260px]" : "ml-[80px]")
                    )}
                >
                    <Header
                        onMenuClick={() => setIsSidebarOpen(!isSidebarOpen)}
                        isMobile={isMobile}
                    />
                    <main className="flex-1 overflow-y-auto p-3 sm:p-4 md:p-6 lg:p-8">
                        {children}
                    </main>
                </div>
            </div>
        </SessionProvider>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Command } from "cmdk";
import { Search, Package, ShoppingCart, Store, X } from "lucide-react";
import { useRouter } from "next/navigation";
import { cn } from "@/lib/utils";

export function CommandPalette() {
    const [open, setOpen] = useState(false);
    const [query, setQuery] = useState("");
    const [results, setResults] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const router = useRouter();

    // Toggle the menu when ΓîÿK is pressed or custom event
    useEffect(() => {
        const down = (e: KeyboardEvent) => {
            if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
                e.preventDefault();
                setOpen((open) => !open);
            }
        };
        const openCustom = () => setOpen(true);

        document.addEventListener("keydown", down);
        window.addEventListener("open-command-palette", openCustom);
        return () => {
            document.removeEventListener("keydown", down);
            window.removeEventListener("open-command-palette", openCustom);
        };
    }, []);

    useEffect(() => {
        if (!query) {
            setResults([]);
            return;
        }

        const fetchResults = async () => {
            setLoading(true);
            try {
                const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`);
                if (res.ok) {
                    const data = await res.json();
                    setResults(data);
                }
            } catch (error) {
                console.error("Search error", error);
            } finally {
                setLoading(false);
            }
        };

        const timer = setTimeout(fetchResults, 300); // Debounce
        return () => clearTimeout(timer);
    }, [query]);

    if (!open) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-start justify-center pt-[15vh] pb-[10vh] px-4 backdrop-blur-sm bg-black/50">
            {/* Click outside to close */}
            <div className="absolute inset-0" onClick={() => setOpen(false)} />

            <div className="relative w-full max-w-xl bg-card border border-border shadow-2xl rounded-xl overflow-hidden shadow-black/50 animate-in fade-in zoom-in-95 duration-200">
                <Command
                    className="w-full flex w-full flex-col bg-transparent"
                    shouldFilter={false} // We handle filtering on backend
                >
                    <div className="flex items-center border-b border-border px-4 py-3">
                        <Search className="mr-3 h-5 w-5 text-muted-foreground" />
                        <Command.Input
                            className="flex-1 bg-transparent border-none text-base outline-none placeholder:text-muted-foreground focus:ring-0 text-foreground"
                            placeholder="Type a command or search (e.g., 'stok keluar hari ini')..."
                            value={query}
                            onValueChange={setQuery}
                            autoFocus
                        />
                        <button onClick={() => setOpen(false)} className="text-muted-foreground hover:text-foreground">
                            <X className="h-5 w-5" />
                        </button>
                    </div>

                    <Command.List className="max-h-[300px] overflow-y-auto p-2 scroll-pb-2 scroll-smooth">
                        {loading && <div className="p-4 text-center text-sm text-muted-foreground">Searching...</div>}

                        {!loading && query && results.length === 0 && (
                            <Command.Empty className="py-6 text-center text-sm text-muted-foreground">
                                No results found for "{query}".
                            </Command.Empty>
                        )}

                        {!loading && results.length > 0 && (
                            <Command.Group heading="Top Results" className="text-xs font-medium text-muted-foreground px-2 py-1.5 [&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:py-1.5 [&_[cmdk-group-heading]]:text-xs [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground">
                                {results.map((result, i) => (
                                    <Command.Item
                                        key={i}
                                        value={result.id || result.title}
                                        onSelect={() => {
                                            if (result.url) {
                                                router.push(result.url);
                                                setOpen(false);
                                            }
                                        }}
                                        className={cn(
                                            "relative flex cursor-pointer select-none items-center rounded-sm px-3 py-2.5 text-sm outline-none",
                                            "aria-selected:bg-accent aria-selected:text-accent-foreground data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
                                            "hover:bg-accent hover:text-accent-foreground w-full"
                                        )}
                                    >
                                        <div className="mr-3 p-1.5 bg-secondary rounded-md">
                                            {result.type === 'product' && <Package className="h-4 w-4 text-cyan-500" />}
                                            {result.type === 'order' && <ShoppingCart className="h-4 w-4 text-emerald-500" />}
                                            {result.type === 'store' && <Store className="h-4 w-4 text-violet-500" />}
                                            {!['product', 'order', 'store'].includes(result.type) && <Search className="h-4 w-4 text-muted-foreground" />}
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="font-medium text-foreground">{result.title}</span>
                                            {result.description && (
                                                <span className="text-xs text-muted-foreground line-clamp-1">{result.description}</span>
                                            )}
                                        </div>
                                    </Command.Item>
                                ))}
                            </Command.Group>
                        )}

                        {!loading && results.length === 5 && (
                            <div className="px-2 py-2 border-t border-border mt-2">
                                <button className="w-full text-center text-xs text-primary hover:underline" onClick={() => {
                                    /* Handle full search page if exists */
                                    setOpen(false);
                                }}>
                                    Lihat semua hasil di halaman penuh
                                </button>
                            </div>
                        )}
                    </Command.List>
                </Command>
            </div>
        </div>
    );
}

"use client";

import { usePathname } from "next/navigation";
import Link from "next/link";
import { Search, Sun, Moon, Bell, Menu, LogOut } from "lucide-react";
import { useTheme } from "next-themes";
import { Button } from "@/components/ui/button";
import { useEffect, useState } from "react";
import { useSession, signOut } from "next-auth/react";
import { CommandPalette } from "./CommandPalette";

interface HeaderProps {
    onMenuClick?: () => void;
    isMobile?: boolean;
}

export function Header({ onMenuClick, isMobile }: HeaderProps) {
    const pathname = usePathname();
    const { theme, setTheme } = useTheme();
    const [mounted, setMounted] = useState(false);
    const [showNotifications, setShowNotifications] = useState(false);
    const { data: session } = useSession();

    useEffect(() => {
        setMounted(true);

        // Register Push Notification Service Worker
        if ('serviceWorker' in navigator && 'PushManager' in window) {
            navigator.serviceWorker.register('/push-sw.js')
                .then(() => console.log('Push SW registered successfully.'))
                .catch(err => console.error('Push SW registration failed:', err));
        }
    }, []);

    const title = pathname === "/" ? "Dashboard" :
        pathname.split("/").pop()?.replace("-", " ");
    const formattedTitle = title ? title.charAt(0).toUpperCase() + title.slice(1) : "";

    // Derive display data from session
    const username = (session?.user as any)?.username ?? "User";
    const email = session?.user?.email ?? "";
    const role = (session?.user as any)?.role ?? "";
    // Avatar: first 2 uppercase chars of username
    const avatarInitials = username.slice(0, 2).toUpperCase();

    // Mock Notifications data
    const notifications = [
        { id: 1, title: 'Draft PO Dibuat', time: '5m ago', read: false, href: '/po-logs' },
        { id: 2, title: 'Stok Maizena Habis!', time: '1h ago', read: false, href: '/products' },
        { id: 3, title: 'Upload Berhasil', time: '2h ago', read: true, href: '/' }
    ];
    const unreadCount = notifications.filter(n => !n.read).length;

    function getNotifHref(n: typeof notifications[0]) {
        if (n.href) return n.href;
        if (n.title.includes('Draft PO')) return '/po-logs';
        if (n.title.includes('Stok') && n.title.includes('Habis')) return '/products';
        return '/';
    }

    // Role badge colors
    const roleColor: Record<string, string> = {
        MANAGER: "bg-violet-500/15 text-violet-600 dark:text-violet-400",
        SPV: "bg-blue-500/15 text-blue-600 dark:text-blue-400",
        STAFF: "bg-slate-500/15 text-slate-600 dark:text-slate-400",
    };

    return (
        <>
            <CommandPalette />
            <header className="flex h-14 md:h-16 shrink-0 items-center justify-between border-b border-border bg-card px-3 md:px-6">
                <div className="flex items-center gap-3">
                    {/* Hamburger menu ΓÇö hanya tampil di mobile */}
                    {isMobile && (
                        <Button variant="ghost" size="icon" onClick={onMenuClick} className="md:hidden h-9 w-9">
                            <Menu className="h-5 w-5" />
                        </Button>
                    )}
                    <h1 className="text-lg md:text-xl font-bold text-foreground truncate">
                        {formattedTitle}
                    </h1>
                </div>

                <div className="flex items-center gap-1 md:gap-3">
                    {/* Search bar ΓÇö hidden on mobile */}
                    <div
                        className="relative hidden md:flex items-center w-48 lg:w-80 cursor-pointer group"
                        onClick={() => window.dispatchEvent(new Event("open-command-palette"))}
                    >
                        <Search className="absolute left-3 h-4 w-4 text-muted-foreground group-hover:text-foreground transition-colors" />
                        <div className="flex items-center justify-between w-full pl-9 pr-3 h-9 bg-secondary/70 border-none rounded-xl text-sm text-muted-foreground hover:bg-secondary transition-colors">
                            <span>Search global...</span>
                            <kbd className="pointer-events-none hidden md:inline-flex h-5 select-none items-center gap-1 rounded border bg-muted px-1.5 font-mono text-[10px] font-medium text-muted-foreground opacity-100">
                                <span className="text-xs">Γîÿ</span>K
                            </kbd>
                        </div>
                    </div>

                    {mounted ? (
                        <Button variant="ghost" size="icon" onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="rounded-full text-secondary-foreground h-9 w-9">
                            {theme === 'dark' ? <Moon className="h-5 w-5" /> : <Sun className="h-5 w-5" />}
                        </Button>
                    ) : (
                        <div className="w-9 h-9" />
                    )}

                    {/* Notification Bell with Dropdown */}
                    <div className="relative">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="relative rounded-full text-secondary-foreground h-9 w-9"
                            onClick={() => setShowNotifications(!showNotifications)}
                        >
                            <Bell className="h-5 w-5" />
                            {unreadCount > 0 && (
                                <span className="absolute top-1.5 right-2 h-2 w-2 rounded-full bg-destructive border-2 border-card"></span>
                            )}
                        </Button>

                        {showNotifications && (
                            <>
                                <div className="fixed inset-0 z-40" onClick={() => setShowNotifications(false)} />
                                <div className="absolute right-0 mt-2 w-72 bg-card border border-border shadow-lg rounded-xl z-50 overflow-hidden animate-in slide-in-from-top-2">
                                    <div className="px-4 py-3 border-b border-border bg-muted/50 flex justify-between items-center">
                                        <span className="font-semibold text-sm text-foreground">Notifications</span>
                                        <span className="text-xs text-lime-700 dark:text-lime-400 cursor-pointer hover:underline">Mark all as read</span>
                                    </div>
                                    <div className="max-h-80 overflow-y-auto">
                                        {notifications.map(n => (
                                            <Link
                                                key={n.id}
                                                href={getNotifHref(n)}
                                                onClick={() => setShowNotifications(false)}
                                                className={`block p-4 border-b border-border last:border-0 hover:bg-muted/50 transition-colors cursor-pointer ${!n.read ? 'bg-primary/5' : ''}`}
                                            >
                                                <div className="flex justify-between items-start gap-2">
                                                    <div>
                                                        <p className={`text-sm ${!n.read ? 'font-medium text-foreground' : 'text-muted-foreground'}`}>{n.title}</p>
                                                        <p className="text-xs text-muted-foreground mt-1">{n.time}</p>
                                                    </div>
                                                    {!n.read && <div className="h-2 w-2 rounded-full bg-lime-600 dark:bg-lime-400 mt-1.5 shrink-0" />}
                                                </div>
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            </>
                        )}
                    </div>

                    {/* User Avatar + Info + Logout */}
                    <div className="flex items-center gap-2 pl-2 md:pl-4 border-l border-border">
                        <div className="h-8 w-8 md:h-9 md:w-9 rounded-full bg-primary flex items-center justify-center font-bold text-primary-foreground text-xs md:text-sm shrink-0">
                            {avatarInitials}
                        </div>
                        <div className="hidden md:flex flex-col text-sm">
                            <div className="flex items-center gap-1.5 leading-none">
                                <span className="font-semibold">{username}</span>
                                {role && (
                                    <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full ${roleColor[role] ?? roleColor.STAFF}`}>
                                        {role}
                                    </span>
                                )}
                            </div>
                            <span className="text-[10px] text-muted-foreground mt-0.5 truncate max-w-[140px]">{email}</span>
                        </div>
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 rounded-full text-muted-foreground hover:text-destructive hover:bg-destructive/10 transition-colors"
                            onClick={() => signOut({ callbackUrl: "/login" })}
                            title="Logout"
                        >
                            <LogOut className="h-4 w-4" />
                        </Button>
                    </div>
                </div>
            </header>
        </>
    );
}

